import netflixlogo from "./images/netflix-logo.png"

const Home=()=>{
    return(
        <div>
            <div className="relative">
                <img src="https://assets.nflxext.com/ffe/siteui/vlv3/cc73e7c7-7860-4ef4-8fc8-1baf24569d2f/web/IN-en-20260126-TRIFECTA-perspective_90d714e8-acc9-4253-ab46-ca6b349c1989_large.jpg" alt="background"/>
                <div className="absolute left-0 top-0">
                    <img src={netflixlogo} alt="logo" className="bg-linear-to-b from-black w-489"/>
                </div>
            </div>
        </div>
    )
}

export default Home;
